     4|export default async function sitemap(): Promise<MetadataRoute.Sitemap> {
     5|  const baseUrl = 'https://fun4me.sunstein.cloud';
     6|  const supabase = await createClient();
     7|
     8|  // Static pages
     9|  const staticPages: MetadataRoute.Sitemap = [
    10|    {
    11|      url: baseUrl,
    12|      lastModified: new Date(),
    13|      changeFrequency: 'daily',
    14|      priority: 1,
    15|    },
    16|    {
    17|      url: `${baseUrl}/ofertas`,
    18|      lastModified: new Date(),
    19|      changeFrequency: 'daily',
    20|      priority: 0.9,
    21|    },
    22|    {
    23|      url: `${baseUrl}/buscar`,
    24|      lastModified: new Date(),
    25|      changeFrequency: 'weekly',
    26|      priority: 0.3,
    27|    },
    28|  ];
    29|
    30|  // Categories
    31|  const { data: categoriesRaw } = await supabase
    32|    .from('categories')
    33|    .select('slug, created_at')
    34|    .eq('is_active', true);
    35|
    36|  const categories = (categoriesRaw || []) as unknown as { slug: string; created_at: string }[];
    37|
    38|  const categoryPages: MetadataRoute.Sitemap = categories.map((cat) => ({
    39|    url: `${baseUrl}/categoria/${cat.slug}`,
    40|    lastModified: new Date(cat.created_at),
    41|    changeFrequency: 'weekly' as const,
    42|    priority: 0.8,
    43|  }));
    44|
    45|  // Products
    46|  const { data: productsRaw } = await supabase
    47|    .from('products')
    48|    .select('slug, updated_at')
    49|    .eq('is_active', true);
    50|
    51|  const products = (productsRaw || []) as unknown as { slug: string; updated_at: string }[];
    52|
    53|  const productPages: MetadataRoute.Sitemap = products.map((product) => ({
    54|    url: `${baseUrl}/producto/${product.slug}`,
    55|    lastModified: new Date(product.updated_at),
    56|    changeFrequency: 'weekly' as const,
    57|    priority: 0.7,
    58|  }));
    59|
    60|  // Kink categories (untyped table)
    61|  let kinkPages: MetadataRoute.Sitemap = [];
    62|  try {
    63|    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    64|    const { data: kinksRaw } = await (supabase as any)
    65|      .from('kink_categories')
    66|      .select('slug, created_at')
    67|      .eq('is_active', true);
    68|
    69|    const kinks = (kinksRaw || []) as { slug: string; created_at: string }[];
    70|
    71|    kinkPages = kinks.map((kink) => ({
    72|      url: `${baseUrl}/kink/${kink.slug}`,
    73|      lastModified: new Date(kink.created_at),
    74|      changeFrequency: 'weekly' as const,
    75|      priority: 0.6,
    76|    }));
    77|  } catch {
    78|    // kink_categories table may not exist
    79|  }
    80|
    81|  return [...staticPages, ...categoryPages, ...productPages, ...kinkPages];
    82|}
